const captured = $json;
const userDoc = $('User Data').first().json;

const update = {};
if (captured.nombre_capturado)    update.nombre    = captured.nombre_capturado;
if (captured.email_capturado)     update.email     = captured.email_capturado;
if (captured.telefono_capturado)  update.telefono  = captured.telefono_capturado;
if (captured.checkin_capturado)   update.checkin   = captured.checkin_capturado;
if (captured.checkout_capturado)  update.checkout  = captured.checkout_capturado;
if (captured.grupo_tipo)          update.grupo_tipo = captured.grupo_tipo;

if (Object.keys(update).length === 0) return [];

const idStr = JSON.stringify(userDoc._id).replace(/^"|"$/g, '');
return [{ json: { _id: idStr, ...update } }];

const agentOutput = $input.first().json.output || '';

let parsed;
try {
  const jsonMatch = agentOutput.match(/\{[\s\S]*\}/);
  parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : null;
} catch(e) {
  parsed = null;
}

const checkin   = parsed?.checkin_capturado  || null;
const checkout  = parsed?.checkout_capturado || null;
const grupoTipo = parsed?.grupo_tipo         || null;
const propiedad = $('Set Propiedad').first().json.propiedad;

function toBookingDate(dateStr) {
  if (!dateStr) return null;
  const m = dateStr.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  return m ? `${m[2]}/${m[3]}/${m[1]}` : null;
}

const dateIn  = toBookingDate(checkin);
const dateOut = toBookingDate(checkout);

const guestMap = {
  romantico:    { adults: 2, children: 0 },
  familia:      { adults: 2, children: 1 },
  grupo_grande: { adults: 4, children: 0 },
};
const fallback = guestMap[grupoTipo] || { adults: 1, children: 0 };
const adultsParsed   = Number.isInteger(parsed?.adultos_capturado) ? parsed.adultos_capturado : null;
const childrenParsed = Number.isInteger(parsed?.ninos_capturado)   ? parsed.ninos_capturado   : null;
const guests = {
  adults:   adultsParsed   !== null ? adultsParsed   : fallback.adults,
  children: childrenParsed !== null ? childrenParsed : fallback.children,
};

const roomCodeMap = {
  ITZ: { romantico: null, familia: null, grupo_grande: null },
  KAA: {
    romantico:    '555466',
    familia:      '532468',
    grupo_grande: '555465',
  },
};
const roomCode = (roomCodeMap[propiedad] || {})[grupoTipo] || null;

const hotelId = propiedad === 'KAA' ? '115718' : '115719';
const baseUrl = propiedad === 'KAA'
  ? (roomCode ? 'https://reservations.kaanabelize.com/book/dates-of-stay' : 'https://reservations.kaanabelize.com/book/accommodations')
  : 'https://reservations.itzanabelize.com/book/accommodations';
const utmCampaign = propiedad === 'KAA' ? 'kaana-f1' : 'itzana-f1';

let deepLink = null;
if (dateIn && dateOut) {
  const enc = encodeURIComponent;
  deepLink = `${baseUrl}?HotelID=${hotelId}&LanguageID=1&Rooms=1&DateIn=${enc(dateIn)}&DateOut=${enc(dateOut)}&Adults=${guests.adults}&Children=${guests.children}`;
  if (roomCode) deepLink += `&RoomTypeID=${roomCode}`;
  deepLink += `&utm_source=kaan-chat&utm_medium=manychat&utm_campaign=${utmCampaign}`;
}

let responseText = parsed?.response || agentOutput;
if (deepLink) {
  responseText = responseText.replace(
    /https?:\/\/(?:reservations\.(?:itzanabelize|kaanabelize)\.com\/book\/(?:accommodations|dates-of-stay)|bookings\.travelclick\.com\/\d+)[^\s]*/g,
    deepLink
  );
}

const categoria = parsed?.categoria || 'info';
if (categoria === 'empleo') {
  responseText = 'Gracias por tu interés — nuestro equipo de Recursos Humanos se comunicará contigo pronto.';
}

return [{
  json: {
    response_text:       responseText,
    escalate:            parsed?.escalate           || false,
    categoria:           categoria,
    nombre_capturado:    parsed?.nombre_capturado   || null,
    email_capturado:     parsed?.email_capturado    || null,
    telefono_capturado:  parsed?.telefono_capturado || null,
    checkin_capturado:   checkin,
    checkout_capturado:  checkout,
    grupo_tipo:          grupoTipo,
    deep_link:           deepLink,
    raw_output:          agentOutput
  }
}];

const current_key = $input.first().json.body.key;

const current_body = $input.first().json.body;

const timestamp = new Date().toISOString();

const start_time = Date.now();

const result_body = {
 current_body,
  timestamp
}

return [{
  key: current_key,
  body: JSON.stringify(result_body),
  timestamp,
  start_time
}]

